// Allowlist: only this chat id may use the bot (it controls your server).
// Replace 0 with YOUR numeric Telegram chat id (get it from @userinfobot).
const ALLOWED_CHAT_ID = 0;
const u = $('Telegram Trigger').first().json;
const cq = u.callback_query;
const msg = u.message;
let chatId, kind, text = '', data = '';
if (cq) { chatId = cq.message && cq.message.chat && cq.message.chat.id; data = cq.data || ''; kind = 'callback'; }
else if (msg) { chatId = msg.chat && msg.chat.id; text = (msg.text || '').trim(); const c = text.toLowerCase(); kind = (c === '/menu' || c === '/start' || c.startsWith('/menu@') || c.startsWith('/start@')) ? 'menu' : 'text'; }
else { return []; }
if (ALLOWED_CHAT_ID && chatId !== ALLOWED_CHAT_ID) return [];
return [{ json: { kind, text, data, chatId } }];

const chatId = $('Guard').first().json.chatId;
const kb = { inline_keyboard: [
  [{ text: 'Estado del servidor', callback_data: 'r:estado' }],
  [{ text: 'Disco', callback_data: 'r:disco' }, { text: 'RAM', callback_data: 'r:ram' }, { text: 'Uptime', callback_data: 'r:uptime' }],
  [{ text: 'SSL', callback_data: 'r:ssl' }, { text: 'Fail2ban', callback_data: 'r:f2b' }, { text: 'Backups', callback_data: 'r:backups' }],
  [{ text: 'Reiniciar nginx', callback_data: 'c:nginx' }, { text: 'Reiniciar n8n', callback_data: 'c:n8n' }],
  [{ text: 'Reiniciar MariaDB', callback_data: 'c:mariadb' }, { text: 'Desbanear IP', callback_data: 'c:unban' }]
] };
return [{ json: { payload: { chat_id: chatId, text: 'Menu DevOps. Elige una opcion:', reply_markup: kb } } }];

const action = $('Parse CB').first().json.action;
const chatId = $('Parse CB').first().json.chatId;
let d = {};
try { d = JSON.parse(($input.first().json.stdout || '{}').toString().trim()); } catch (e) {}
const s = d.services || {};
const ok = v => String(v).startsWith('OK') ? 'OK' : 'FAIL';
let text;
switch (action) {
  case 'r:estado':
    text = ['Estado del servidor', 'nginx: ' + ok(s.nginx), 'MariaDB: ' + ok(s.mariadb), 'n8n: ' + ok(s.n8n), 'Web principal: ' + ok(s.web_main), 'Web app: ' + ok(s.web_app), 'Disco: ' + d.disk_pct + '% | RAM: ' + d.ram_pct + '%', d.uptime || ''].join('\n');
    break;
  case 'r:disco': text = 'Disco: ' + d.disk_pct + '%'; break;
  case 'r:ram': text = 'RAM: ' + d.ram_pct + '%'; break;
  case 'r:uptime': text = 'Uptime: ' + (d.uptime || '-'); break;
  case 'r:ssl': text = 'SSL:\n' + (d.ssl || []).map(c => c.name + ': ' + c.days + ' dias').join('\n'); break;
  case 'r:f2b': { const f = d.fail2ban || {}; text = ['Fail2ban (sshd)', 'Baneadas ahora: ' + f.cur_banned + ' (total ' + f.tot_banned + ')', 'Fallos: ' + f.cur_failed + ' (total ' + f.tot_failed + ')', 'IPs: ' + (f.banned_ips || '-')].join('\n'); break; }
  case 'r:backups': { const b = d.backups || {}; text = ['Backups', 'Hoy (' + b.today + '): ' + (b.today_count > 0 ? 'OK' : 'sin copia aun'), 'Ultima: ' + (b.newest || '-')].join('\n'); break; }
  default: text = 'Opcion no reconocida.';
}
return [{ json: { payload: { chat_id: chatId, text } } }];

const a = $('Parse CB').first().json.action;
const chatId = $('Parse CB').first().json.chatId;
const labels = { 'c:nginx': 'reiniciar nginx', 'c:n8n': 'reiniciar n8n', 'c:mariadb': 'reiniciar MariaDB' };
const okData = { 'c:nginx': 'ok:nginx', 'c:n8n': 'ok:n8n', 'c:mariadb': 'ok:mariadb' };
const text = 'Vas a ' + (labels[a] || a) + '. Confirmas?';
const kb = { inline_keyboard: [[{ text: 'Confirmar', callback_data: okData[a] }, { text: 'Cancelar', callback_data: 'x' }]] };
return [{ json: { payload: { chat_id: chatId, text, reply_markup: kb } } }];

const chatId = $('Parse CB').first().json.chatId;
let d = {};
try { d = JSON.parse(($input.first().json.stdout || '{}').toString().trim()); } catch (e) {}
const ips = (((d.fail2ban || {}).banned_ips) || '').trim().split(/\s+/).filter(Boolean);
if (!ips.length) { return [{ json: { payload: { chat_id: chatId, text: 'No hay IPs baneadas ahora.' } } }]; }
const rows = ips.map(ip => [{ text: 'Desbanear ' + ip, callback_data: 'ok:unban:' + ip }]);
rows.push([{ text: 'Cancelar', callback_data: 'x' }]);
return [{ json: { payload: { chat_id: chatId, text: 'IPs baneadas. Toca para desbanear:', reply_markup: { inline_keyboard: rows } } } }];

const a = $('Parse CB').first().json.action;
const chatId = $('Parse CB').first().json.chatId;
const map = { 'ok:nginx': 'restart_nginx.sh', 'ok:n8n': 'restart_n8n.sh', 'ok:mariadb': 'restart_mariadb.sh' };
let cmd;
if (a.startsWith('ok:unban:')) { const ip = a.slice(9); cmd = 'sudo -n /opt/vertiguard/unban_ip.sh ' + ip; }
else if (map[a]) { cmd = 'sudo -n /opt/vertiguard/' + map[a]; }
else { cmd = 'echo {}'; }
return [{ json: { command: cmd, chatId } }];

const chatId = $('Build control cmd').first().json.chatId;
let d = {};
try { d = JSON.parse(($input.first().json.stdout || '{}').toString().trim()); } catch (e) {}
let text;
if (d.action === 'unban_ip') { text = d.ok ? ('IP desbaneada: ' + d.ip) : ('No se pudo desbanear: ' + (d.error || '?')); }
else if (d.action) { const name = ({ restart_nginx: 'nginx', restart_n8n: 'n8n', restart_mariadb: 'MariaDB' })[d.action] || d.action; text = d.ok ? (name + ' reiniciado correctamente (' + d.state + ').') : (name + ' fallo al reiniciar (' + (d.state || '?') + ').'); }
else { text = 'Accion ejecutada.'; }
return [{ json: { payload: { chat_id: chatId, text } } }];

const chatId = $('Guard').first().json.chatId;
const out = ($input.first().json.output || 'Sin respuesta.').toString();
return [{ json: { payload: { chat_id: chatId, text: out } } }];
